import{_ as e,o as a,c,ag as o}from"./chunks/framework-C5-Jzrz4.js";const i=JSON.parse('{"title":"Captcha 验证码能力","description":"@vben/common-ui 的验证码组件集合，包含点选、滑块、旋转和拼图校验","frontmatter":{"title":"Captcha 验证码能力","description":"@vben/common-ui 的验证码组件集合，包含点选、滑块、旋转和拼图校验","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/captcha.md","filePath":"scripts/components/common-ui/captcha.md","lastUpdated":null}');const l=e({name:"scripts/components/common-ui/captcha.md"},[["render",function(e,i,l,t,d,n){return a(),c("div",null,[...i[0]||(i[0]=[o('<h1 id="captcha" tabindex="-1"><code>Captcha</code> <a class="header-anchor" href="#captcha" aria-label="Permalink to &quot;`Captcha`&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>packages/effects/common-ui/src/components/captcha</code> 提供一组前端验证码组件，不是单一组件，而是按验证码形态拆分的能力集合。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>登录、注册、找回密码等高风险表单</li><li>需要前端完成交互式校验的场景</li><li>需要在通过验证后回调业务逻辑的场景</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/effects/common-ui/src/components/captcha/index.ts</code></li><li><code>packages/effects/common-ui/src/components/captcha/types.ts</code></li><li><code>packages/effects/common-ui/src/components/captcha/point-selection-captcha/index.vue</code></li><li><code>packages/effects/common-ui/src/components/captcha/slider-captcha/index.vue</code></li><li><code>packages/effects/common-ui/src/components/captcha/slider-rotate-captcha/index.vue</code></li><li><code>packages/effects/common-ui/src/components/captcha/slider-translate-captcha/index.vue</code></li></ul><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><ul><li><code>PointSelectionCaptcha</code></li><li><code>PointSelectionCaptchaCard</code></li><li><code>SliderCaptcha</code></li><li><code>SliderRotateCaptcha</code></li><li><code>SliderTranslateCaptcha</code></li></ul><h3 id="点选验证码" tabindex="-1">点选验证码 <a class="header-anchor" href="#点选验证码" aria-label="Permalink to &quot;点选验证码&quot;">​</a></h3><ul><li><code>PointSelectionCaptcha</code> 内部维护点击点位列表。</li><li>组件会在点击时计算相对坐标，并通过 <code>click</code> 事件抛出 <code>CaptchaPoint</code>。</li><li><code>showConfirm</code> 打开后会增加确认按钮，并通过 <code>confirm(points, clear)</code> 事件通知外部。</li><li><code>hintImage</code> 和 <code>hintText</code> 至少需要提供一个，否则源码会报警告。</li></ul><h3 id="滑块验证码" tabindex="-1">滑块验证码 <a class="header-anchor" href="#滑块验证码" aria-label="Permalink to &quot;滑块验证码&quot;">​</a></h3><ul><li><code>SliderCaptcha</code> 是通用滑条容器，使用 <code>v-model</code> 管理通过状态。</li><li>组件会发出 <code>start</code>、<code>move</code>、<code>end</code>、<code>success</code> 事件。</li><li>组件暴露 <code>resume()</code>，可在失败后重置滑块。</li></ul><h3 id="旋转验证码" tabindex="-1">旋转验证码 <a class="header-anchor" href="#旋转验证码" aria-label="Permalink to &quot;旋转验证码&quot;">​</a></h3><ul><li><code>SliderRotateCaptcha</code> 在图片加载后生成随机角度。</li><li>用户拖动滑块时，组件根据滑动距离计算当前旋转角度。</li><li>当误差小于 <code>diffDegree</code> 时视为通过，并发出 <code>success</code>。</li></ul><h3 id="拼图验证码" tabindex="-1">拼图验证码 <a class="header-anchor" href="#拼图验证码" aria-label="Permalink to &quot;拼图验证码&quot;">​</a></h3><ul><li><code>SliderTranslateCaptcha</code> 使用 <code>canvas</code> 裁切拼图块。</li><li>组件通过拖动滑块控制拼图块水平位置。</li><li>验证成功后同样通过 <code>success</code> 事件抛出时间信息。</li></ul><h2 id="使用方式与注意事项" tabindex="-1">使用方式与注意事项 <a class="header-anchor" href="#使用方式与注意事项" aria-label="Permalink to &quot;使用方式与注意事项&quot;">​</a></h2><ul><li><code>PointSelectionCaptchaCard</code> 和 <code>PointSelectionCaptcha</code> 当前指向同一个 <code>index.vue</code> 导出。</li><li><code>SliderCaptcha</code> 可通过 <code>isSlot</code> 作为联动容器使用，旋转和拼图验证码都基于它实现。</li><li>验证码图片涉及跨域时，源码会尝试设置 <code>crossOrigin</code>，但仍需要后端或静态资源正确支持 CORS。</li><li>这组组件偏交互，不应当和通用表单输入组件混为一类。</li></ul>',20)])])}]]);export{i as __pageData,l as default};
